// Node.js crypto module to generate password hashes
const crypto = require('crypto');

function setRememberMeCookie(req, res, username, password) {
  // Generate a hash of the user's password
  const passwordHash = crypto.createHash('sha256').update(password).digest('hex');
  
  // Set cookie to expire in 30 days
  const expires = new Date();
  expires.setDate(expires.getDate() + 30);

  res.cookie('rememberMe', `${username}:${passwordHash}`, { expires: expires });
  
  // Send a response to the client
  res.send("Remember Me cookie set");
}

function autoLogin(req, res) {
  const rememberMeCookie = req.cookies['rememberMe'];

  if (rememberMeCookie) {
    // Split username and password hash from the cookie data
    const [username, storedPasswordHash] = rememberMeCookie.split(':');
    
    // Get user's current password and generate a new hash
    const userPassword = getUserPassword(username);  // This function is not provided in this snippet
    const enteredPasswordHash = crypto.createHash('sha256').update(userPassword).digest('hex');
    
    if (enteredPasswordHash === storedPasswordHash) {
      res.send("User auto-logged in");
    } else {
      // If the password hash doesn't match, clear the cookie and prompt for login again
      res.clearCookie('rememberMe');
      res.redirect('/login');  // Redirect to login page
    }
  } else {
    res.send("No Remember Me cookie found");
  }
}